537: absl::StatusOr<bool> ListenerManagerImpl::addOrUpdateListenerInternal(
538:     const envoy::config::listener::v3::Listener& config, const std::string& version_info,
539:     bool added_via_api, const std::string& name) {
540: 
541:   if (listenersStopped(config)) {
542:     ENVOY_LOG(
543:         debug,
544:         "listener {} can not be added because listeners in the traffic direction {} are stopped",
545:         name, envoy::config::core::v3::TrafficDirection_Name(config.traffic_direction()));
546:     return false;
547:   }
548: 
549:   const uint64_t hash = MessageUtil::hash(config);
550:   ENVOY_LOG(debug, "begin add/update listener: name={} hash={}", name, hash);
551: 
552:   auto existing_active_listener = getListenerByName(active_listeners_, name);
553:   auto existing_warming_listener = getListenerByName(warming_listeners_, name);
554: 
555:   // The listener should be updated back to its original state and the warming listener should be
556:   // removed.
557:   if (existing_warming_listener != warming_listeners_.end() &&
558:       existing_active_listener != active_listeners_.end() &&
559:       (*existing_active_listener)->blockUpdate(hash)) {
560:     warming_listeners_.erase(existing_warming_listener);
561:     updateWarmingActiveGauges();
562:     stats_.listener_modified_.inc();
563:     return true;
564:   }
565: 
566:   // Do a quick blocked update check before going further. This check needs to be done against both
567:   // warming and active.
568:   if ((existing_warming_listener != warming_listeners_.end() &&
569:        (*existing_warming_listener)->blockUpdate(hash)) ||
570:       (existing_active_listener != active_listeners_.end() &&
571:        (*existing_active_listener)->blockUpdate(hash))) {
572:     ENVOY_LOG(debug, "duplicate/locked listener '{}'. no add/update", name);
573:     return false;
574:   }
575: 
576:   ListenerImplPtr new_listener = nullptr;
577: 
578:   // In place filter chain update depends on the active listener at worker.
579:   if (existing_active_listener != active_listeners_.end() &&
580:       (*existing_active_listener)->supportUpdateFilterChain(config, workers_started_)) {
581:     ENVOY_LOG(debug, "use in place update filter chain update path for listener name={} hash={}",
582:               name, hash);
583:     auto listener_or_error =
584:         (*existing_active_listener)->newListenerWithFilterChain(config, workers_started_, hash);
585:     RETURN_IF_NOT_OK_REF(listener_or_error.status());
586:     new_listener = std::move(*listener_or_error);
587:     stats_.listener_in_place_updated_.inc();
588:   } else {
589:     ENVOY_LOG(debug, "use full listener update path for listener name={} hash={}", name, hash);
590:     auto listener_or_error = ListenerImpl::create(config, version_info, *this, name, added_via_api,
591:                                                   workers_started_, hash);
592:     RETURN_IF_NOT_OK_REF(listener_or_error.status());
593:     new_listener = std::move(*listener_or_error);
594:   }
595: 
596:   ListenerImpl& new_listener_ref = *new_listener;
597: 
598:   bool added = false;
599:   if (existing_warming_listener != warming_listeners_.end()) {
600:     ASSERT(workers_started_);
601:     new_listener->debugLog("update warming listener");
602:     RETURN_IF_NOT_OK(setupSocketFactoryForListener(*new_listener, **existing_warming_listener));
603:     // In this case we can just replace inline.
604:     *existing_warming_listener = std::move(new_listener);
605:   } else if (existing_active_listener != active_listeners_.end()) {
606:     RETURN_IF_NOT_OK(setupSocketFactoryForListener(*new_listener, **existing_active_listener));
607:     // In this case we have no warming listener, so what we do depends on whether workers
608:     // have been started or not.
609:     if (workers_started_) {
610:       new_listener->debugLog("add warming listener");
611:       warming_listeners_.emplace_back(std::move(new_listener));
612:     } else {
613:       new_listener->debugLog("update active listener");
614:       *existing_active_listener = std::move(new_listener);
615:     }
616:   } else {
617:     // We have no warming or active listener so we need to make a new one. What we do depends on
618:     // whether workers have been started or not.
619:     RETURN_IF_NOT_OK(setNewOrDrainingSocketFactory(name, *new_listener));
620:     if (workers_started_) {
621:       new_listener->debugLog("add warming listener");
622:       warming_listeners_.emplace_back(std::move(new_listener));
623:     } else {
624:       new_listener->debugLog("add active listener");
625:       active_listeners_.emplace_back(std::move(new_listener));
626:     }
627: 
628:     added = true;
629:   }
630: 
631:   updateWarmingActiveGauges();
632:   if (added) {
633:     stats_.listener_added_.inc();
634:   } else {
635:     stats_.listener_modified_.inc();
636:   }
637: 
638:   new_listener_ref.initialize();
639:   return true;
640: }
