697: ListenerManagerImpl::ListenerList::iterator
698: ListenerManagerImpl::getListenerByName(ListenerList& listeners, const std::string& name) {
699:   auto ret = listeners.end();
700:   for (auto it = listeners.begin(); it != listeners.end(); ++it) {
701:     if ((*it)->name() == name) {
702:       // There should only ever be a single listener per name in the list. We could return faster
703:       // but take the opportunity to assert that fact.
704:       ASSERT(ret == listeners.end());
705:       ret = it;
706:     }
707:   }
708:   return ret;
709: }
