711: std::vector<std::reference_wrapper<Network::ListenerConfig>>
712: ListenerManagerImpl::listeners(ListenerState state) {
713:   std::vector<std::reference_wrapper<Network::ListenerConfig>> ret;
714: 
715:   size_t size = 0;
716:   size += state & WARMING ? warming_listeners_.size() : 0;
717:   size += state & ACTIVE ? active_listeners_.size() : 0;
718:   size += state & DRAINING ? draining_listeners_.size() : 0;
719:   ret.reserve(size);
720: 
721:   if (state & WARMING) {
722:     for (const auto& listener : warming_listeners_) {
723:       ret.push_back(*listener);
724:     }
725:   }
726:   if (state & ACTIVE) {
727:     for (const auto& listener : active_listeners_) {
728:       ret.push_back(*listener);
729:     }
730:   }
731:   if (state & DRAINING) {
732:     for (const auto& draining_listener : draining_listeners_) {
733:       ret.push_back(*(draining_listener.listener_));
734:     }
735:   }
736:   return ret;
737: }
