942: absl::Status ListenerManagerImpl::startWorkers(OptRef<GuardDog> guard_dog,
943:                                                std::function<void()> callback) {
944:   ENVOY_LOG(info, "all dependencies initialized. starting workers");
945:   ASSERT(!workers_started_);
946:   workers_started_ = true;
947:   uint32_t i = 0;
948: 
949:   absl::BlockingCounter workers_waiting_to_run(workers_.size());
950:   std::function<void()> worker_started_running = [&workers_waiting_to_run]() {
951:     workers_waiting_to_run.DecrementCount();
952:   };
953: 
954:   // We can not use "Cleanup" to simplify this logic here, because it results in a issue if Envoy is
955:   // killed before workers are actually started. Specifically the AdminRequestGetStatsAndKill test
956:   // case in main_common_test fails with ASAN error if we use "Cleanup" here.
957:   const auto listeners_pending_init =
958:       std::make_shared<std::atomic<uint64_t>>(workers_.size() * active_listeners_.size());
959:   ASSERT(warming_listeners_.empty());
960:   // We need to protect against inline deletion so have to use iterators directly.
961:   for (auto listener_it = active_listeners_.begin(); listener_it != active_listeners_.end();) {
962:     auto& listener = *listener_it;
963:     listener_it++;
964: 
965:     absl::StatusOr<bool> init_status = doFinalPreWorkerListenerInit(*listener);
966:     RETURN_IF_NOT_OK_REF(init_status.status());
967: 
968:     if (!*init_status) {
969:       incListenerCreateFailureStat();
970:       removeListenerInternal(listener->name(), false);
971:       continue;
972:     }
973:     for (const auto& worker : workers_) {
974:       addListenerToWorker(*worker, absl::nullopt, *listener,
975:                           [this, listeners_pending_init, callback]() {
976:                             if (--(*listeners_pending_init) == 0) {
977:                               stats_.workers_started_.set(1);
978:                               callback();
979:                             }
980:                           });
981:     }
982:   }
983:   for (const auto& worker : workers_) {
984:     ENVOY_LOG(debug, "starting worker {}", i);
985:     worker->start(guard_dog, worker_started_running);
986:     if (enable_dispatcher_stats_) {
987:       worker->initializeStats(*scope_);
988:     }
989:     i++;
990:   }
991: 
992:   // Wait for workers to start running.
993:   workers_waiting_to_run.Wait();
994: 
995:   if (active_listeners_.empty()) {
996:     stats_.workers_started_.set(1);
997:     callback();
998:   }
999:   return absl::OkStatus();
1000: }
