132:     Configuration::ListenerFactoryContext& context,
133:     Filter::TcpListenerFilterConfigProviderManagerImpl& config_provider_manager) {
134:   Filter::ListenerFilterFactoriesList ret;
135: 
136:   ret.reserve(filters.size());
137:   for (ssize_t i = 0; i < filters.size(); i++) {
138:     const auto& proto_config = filters[i];
139:     ENVOY_LOG(debug, "  filter #{}:", i);
140:     ENVOY_LOG(debug, "    name: {}", proto_config.name());
141:     // dynamic listener filter configuration
142:     if (proto_config.config_type_case() ==
143:         envoy::config::listener::v3::ListenerFilter::ConfigTypeCase::kConfigDiscovery) {
144:       const auto& config_discovery = proto_config.config_discovery();
145:       const auto& name = proto_config.name();
146:       if (config_discovery.apply_default_config_without_warming() &&
147:           !config_discovery.has_default_config()) {
148:         return absl::InvalidArgumentError(fmt::format(
149:             "Error: listener filter config {} applied without warming but has no default config.",
150:             name));
151:       }
152:       for (const auto& type_url : config_discovery.type_urls()) {
153:         const auto factory_type_url = TypeUtil::typeUrlToDescriptorFullName(type_url);
154:         const auto* factory =
155:             Registry::FactoryRegistry<Server::Configuration::NamedListenerFilterConfigFactory>::
156:                 getFactoryByType(factory_type_url);
157:         if (factory == nullptr) {
158:           return absl::InvalidArgumentError(fmt::format(
159:               "Error: no listener factory found for a required type URL {}.", factory_type_url));
160:         }
161:       }
162:       auto filter_config_provider = config_provider_manager.createDynamicFilterConfigProvider(
163:           config_discovery, name, context.serverFactoryContext(), context,
164:           context.serverFactoryContext().clusterManager(), false, "tcp-listener",
165:           createListenerFilterMatcher(proto_config));
166:       ret.push_back(std::move(filter_config_provider));
167:     } else {
168:       ENVOY_LOG(debug, "  config: {}",
169:                 MessageUtil::convertToStringForLogs(
170:                     static_cast<const Protobuf::Message&>(proto_config.typed_config())));
171:       // For static configuration, now see if there is a factory that will accept the config.
172:       auto& factory =
173:           Config::Utility::getAndCheckFactory<Configuration::NamedListenerFilterConfigFactory>(
174:               proto_config);
175:       const auto message = Config::Utility::translateToFactoryConfig(
176:           proto_config, context.messageValidationVisitor(), factory);
177:       const auto callback = factory.createListenerFilterFactoryFromProto(
178:           *message, createListenerFilterMatcher(proto_config), context);
179:       auto filter_config_provider =
180:           config_provider_manager.createStaticFilterConfigProvider(callback, proto_config.name());
181:       ret.push_back(std::move(filter_config_provider));
182:     }
183:   }
184:   return ret;
185: }
