1069: 
1070: absl::StatusOr<Network::DrainableFilterChainSharedPtr>
1071: ListenerFilterChainFactoryBuilder::buildFilterChainInternal(
1072:     const envoy::config::listener::v3::FilterChain& filter_chain,
1073:     Configuration::FilterChainFactoryContextPtr&& filter_chain_factory_context) const {
1074:   // If the cluster doesn't have transport socket configured, then use the default "raw_buffer"
1075:   // transport socket or BoringSSL-based "tls" transport socket if TLS settings are configured.
1076:   // We copy by value first then override if necessary.
1077:   auto transport_socket = filter_chain.transport_socket();
1078:   if (!filter_chain.has_transport_socket()) {
1079:     envoy::extensions::transport_sockets::raw_buffer::v3::RawBuffer raw_buffer;
1080:     transport_socket.mutable_typed_config()->PackFrom(raw_buffer);
1081:     transport_socket.set_name("envoy.transport_sockets.raw_buffer");
1082:   }
1083: 
1084:   auto& config_factory = Config::Utility::getAndCheckFactory<
1085:       Server::Configuration::DownstreamTransportSocketConfigFactory>(transport_socket);
1086:   // The only connection oriented UDP transport protocol right now is QUIC.
1087:   const bool is_quic =
1088:       listener_.udpListenerConfig().has_value() &&
1089:       !listener_.udpListenerConfig()->listenerFactory().isTransportConnectionless();
1090: #if defined(ENVOY_ENABLE_QUIC)
1091:   if (is_quic &&
1092:       dynamic_cast<Quic::QuicServerTransportSocketConfigFactory*>(&config_factory) == nullptr) {
1093:     return absl::InvalidArgumentError(
1094:         fmt::format("error building filter chain for quic listener: wrong "
1095:                     "transport socket config specified for quic transport socket: "
1096:                     "{}. \nUse QuicDownstreamTransport instead.",
1097:                     transport_socket.DebugString()));
1098:   }
1099:   const std::string hcm_str =
1100:       "type.googleapis.com/"
1101:       "envoy.extensions.filters.network.http_connection_manager.v3.HttpConnectionManager";
1102:   if (is_quic &&
1103:       (filter_chain.filters().empty() ||
1104:        filter_chain.filters(filter_chain.filters().size() - 1).typed_config().type_url() !=
1105:            hcm_str)) {
1106:     return absl::InvalidArgumentError(
1107:         fmt::format("error building network filter chain for quic listener: requires "
1108:                     "http_connection_manager filter to be last in the chain."));
1109:   }
1110: #else
1111:   // When QUIC is compiled out it should not be possible to configure either the QUIC transport
1112:   // socket or the QUIC listener and get to this point.
1113:   ASSERT(!is_quic);
1114: #endif
1115:   ProtobufTypes::MessagePtr message =
1116:       Config::Utility::translateToFactoryConfig(transport_socket, validator_, config_factory);
1117: 
1118:   std::vector<std::string> server_names(filter_chain.filter_chain_match().server_names().begin(),
1119:                                         filter_chain.filter_chain_match().server_names().end());
1120: 
1121:   auto factory_or_error = config_factory.createTransportSocketFactory(*message, factory_context_,
1122:                                                                       std::move(server_names));
1123:   RETURN_IF_NOT_OK(factory_or_error.status());
1124:   auto factory_list_or_error = listener_component_factory_.createNetworkFilterFactoryList(
1125:       filter_chain.filters(), *filter_chain_factory_context);
1126:   RETURN_IF_NOT_OK(factory_list_or_error.status());
1127: 
1128:   auto filter_chain_res = std::make_shared<FilterChainImpl>(
1129:       std::move(factory_or_error.value()), std::move(*factory_list_or_error),
1130:       std::chrono::milliseconds(
1131:           PROTOBUF_GET_MS_OR_DEFAULT(filter_chain, transport_socket_connect_timeout, 0)),
1132:       filter_chain.name());
1133: 
1134:   filter_chain_res->setFilterChainFactoryContext(std::move(filter_chain_factory_context));
1135:   return filter_chain_res;
1136: }
1137: 
1138: absl::Status ListenerManagerImpl::setNewOrDrainingSocketFactory(const std::string& name,
1139:                                                                 ListenerImpl& listener) {
1140:   if (hasListenerWithDuplicatedAddress(warming_listeners_, listener) ||
1141:       hasListenerWithDuplicatedAddress(active_listeners_, listener)) {
1142:     const std::string message =
1143:         fmt::format("error adding listener: '{}' has duplicate address '{}' as existing listener",
1144:                     name, absl::StrJoin(listener.addresses(), ",", Network::AddressStrFormatter()));
1145:     ENVOY_LOG(warn, "{}", message);
1146:     return absl::InvalidArgumentError(message);
1147:   }
1148: 
1149:   // Search through draining listeners to see if there is a listener that has a socket factory for
1150:   // the same address we are configured for. This is an edge case, but
1151:   // may happen if a listener is removed and then added back with a same or different name and
1152:   // intended to listen on the same address. This should work and not fail.
1153:   const ListenerImpl* draining_listener_ptr = nullptr;
1154:   auto existing_draining_listener =
1155:       std::find_if(draining_listeners_.cbegin(), draining_listeners_.cend(),
1156:                    [&listener](const DrainingListener& draining_listener) {
1157:                      return draining_listener.listener_->listenSocketFactories()[0]
1158:                                 ->getListenSocket(0)
1159:                                 ->isOpen() &&
1160:                             listener.hasCompatibleAddress(*draining_listener.listener_);
1161:                    });
1162: 
1163:   if (existing_draining_listener != draining_listeners_.cend()) {
1164:     existing_draining_listener->listener_->debugLog("clones listener sockets");
1165:     draining_listener_ptr = existing_draining_listener->listener_.get();
1166:   } else {
1167:     auto existing_draining_filter_chain = std::find_if(
1168:         draining_filter_chains_manager_.cbegin(), draining_filter_chains_manager_.cend(),
1169:         [&listener](const DrainingFilterChainsManager& draining_filter_chain) {
1170:           return draining_filter_chain.getDrainingListener()
1171:                      .listenSocketFactories()[0]
1172:                      ->getListenSocket(0)
1173:                      ->isOpen() &&
1174:                  listener.hasCompatibleAddress(draining_filter_chain.getDrainingListener());
1175:         });
1176: 
1177:     if (existing_draining_filter_chain != draining_filter_chains_manager_.cend()) {
1178:       existing_draining_filter_chain->getDrainingListener().debugLog("clones listener socket");
1179:       draining_listener_ptr = &existing_draining_filter_chain->getDrainingListener();
1180:     }
1181:   }
1182: 
1183:   if (draining_listener_ptr != nullptr) {
1184:     RETURN_IF_NOT_OK(listener.cloneSocketFactoryFrom(*draining_listener_ptr));
1185:   } else {
1186:     return createListenSocketFactory(listener);
1187:   }
1188:   return absl::OkStatus();
1189: }
